      "content": "const { randomUUID } = require('node:crypto');
const { sendError } = require('../../lib/errors');

let projects = {};

function getProject(projectId) {
  return projects[projectId] || null;
}

function createProject(name) {
  if (!name) {
    return null;
  }
  const projectId = randomUUID();
  projects[projectId] = { id: projectId, name, members: [], tasks: [] };
  return projects[projectId];
}

function addMemberToProject(projectId, userId, role) {
  const project = getProject(projectId);
  if (!project) {
    return null;
  }
  if (project.members.some(member => member.userId === userId)) {
    return 'duplicate';
  }
  project.members.push({ userId, role });
  return project;
}

module.exports = { getProject, createProject, addMemberToProject };
