      "content": "const express = require('express');
const router = express.Router();
const { sendError } = require('../../lib/errors');
const { getProject, createProject, addMemberToProject } = require('./service');

router.get('/:projectId', (req, res) => {
  const project = getProject(req.params.projectId);
  if (!project) {
    return sendError(res, 404, 'NOT_FOUND', 'Project not found');
  }
  res.json({ project });
});

router.post('/', (req, res) => {
  const { name } = req.body;
  const project = createProject(name);
  if (!project) {
    return sendError(res, 400, 'INVALID_NAME', 'Name is required');
  }
  res.status(201).json({ project });
});

router.post('/:projectId/members', (req, res) => {
  const { projectId } = req.params;
  const { userId, role } = req.body;
  const result = addMemberToProject(projectId, userId, role);
  if (!result) {
    return sendError(res, 404, 'NOT_FOUND', 'Project not found');
  }
  if (result === 'duplicate') {
    return sendError(res, 409, 'DUPLICATE_MEMBER', 'Member already exists in the project');
  }
  res.status(201).json({ project: result });
});

module.exports = router;
